                                        className={`h-full transition-all duration-500 ${isLowHp ? 'bg-red-500 shadow-[0_0_5px_rgba(239,68,68,0.5)]' : 'bg-red-600'}`} 
                                        style={{ width: `${hpPer}%` }} 
                                    />
                                </div>
                            </div>

                            {/* Vitals: MP */}
